The table shows some values for $y = x^3 + 4x^2 - 4$.

\vgap

\relinput{Figures/Q02-Table.tex}

\vgap

\begin{parts}
    \item Complete the table. 
    \Marks{2}

    \item On the grid, draw the graph of $y = x^3 + 4x^2 - 4$ for $-4.5 \leqslant x \leqslant 1.5$.

    \relinput{Figures/Q02-Grid.tex}

    \Marks{4}

    \item % (c)
    \begin{subparts}
        \item Draw the tangent to the graph at the point $(1, 1)$.
        \Marks{1}
        \item Use your tangent to estimate the gradient of the curve at the point $(1, 1)$.
        \AnswerLine[][]
        \Marks{2}
    \end{subparts}

    \item By drawing a suitable straight line on the grid, solve the equation $x^3 + 4x^2 - x - 6 = 0$.

    \hfill \AnswerLineShort[$x=$][] or \AnswerLineShort[$x=$][] or \AnswerLineShort[$x=$][]
    \Marks{4}
\end{parts}

\begin{parts}
    \item Simplify. % (a)
    \begin{subparts}
        \item $3m - 5n - 4m + 8n$
        \AnswerLine[][]
        \Marks{2}

        \item $(3a^2 c^3)^4$
        \AnswerLine[][]
        \Marks{2}

        \item $\dfrac{4x}{5} - \dfrac{3x}{10} + \dfrac{2x}{15}$
        \AnswerLine[][]
        \Marks{2}
    \end{subparts}

    \item This isosceles triangle has a perimeter of $35.5$ cm. % (b)

    \relinput{Figures/Q03-Triangle.tex}

    \vgap

    Find the value of $a$.
    \AnswerLine[$a = $][]
    \Marks{3}

    \item Using the quadratic formula, solve $5x^2 - 4x - 3 = 0$. % (c)

    You must show all your working.

    \hfill \AnswerLineShort[$x=$][] or \AnswerLineShort[$x=$][]
    \Marks{3}

    \item Solve these simultaneous equations. % (d)
    \[ y = x^2 - 4x + 5 \]
    \[ y = 2x - 3 \]

    You must show all your working.

    \hfill \AnswerLineShort[$x = $][], $y = $\AnswerLineShort[][]

    \vgap

    \hfill \AnswerLineShort[$x = $][], $y = $\AnswerLineShort[][]
    \Marks{5}
\end{parts}

\begin{parts}
    \item The angles of a quadrilateral are $w^\circ, x^\circ, y^\circ$ and $z^\circ$. % (a)

    The ratio $w : (x + y + z) = 3 : 5$.

    \vgap

    Find the value of $w$.
    \AnswerLine[$w = $][]
    \Marks{2}

    \item \, % (b)

    \relinput{Figures/Q04-Circle1.tex}

    \vgap

    $A, B, C$ and $D$ are points on a circle.

    $PQ$ is the tangent to the circle at $A$.

    $BMND$ is a straight line.

    Angle $ACD = 49^\circ$, angle $AMB = 105^\circ$ and angle $PAB = 45^\circ$.
    \begin{subparts}
        \item Find angle $BAM$.
        \AnswerLine[Angle $BAM = $][]
        \Marks{2}

        \item % (ii)
        \begin{subsubparts}
            \item Find angle $BAD$.
            \AnswerLine[Angle $BAD = $][]
            \Marks{2}

            \item Give a geometrical reason why $BD$ is not the diameter of the circle.

            \vgap

            \dotfill

            \vgap

            \dotfill

            \Marks{1}
        \end{subsubparts}
    \end{subparts}

    \item \, % (c)

    \relinput{Figures/Q04-Circle2.tex}

    \vgap

    $A, B, C$ and $D$ are points on a circle, centre $O$.

    $TA$ and $TC$ are tangents to the circle.

    $OA = 6.75$ cm and $OT = 11.5$ cm.
    \begin{subparts}
        \item Show that angle $AOC = 108.12^\circ$, correct to 2 decimal places.
        \vgap
        \Marks{3}

        \item Calculate the length of the minor arc $ABC$.
        \AnswerLine[][cm]
        \Marks{2}

        \item Calculate the area of the major sector $OCDA$.
        \AnswerLine[][cm$^2$]
        \Marks{3}
    \end{subparts}
\end{parts}

\begin{parts}
    \item The cumulative frequency diagram shows information about the distance travelled by each of 80 motorists in a month. % (a)

    \relinput{Figures/Q05-CumFreq.tex}

    \begin{subparts}
        \item Use the cumulative frequency diagram to find an estimate for
        \begin{subsubparts}
            \item the median
            \AnswerLine[][km]
            \Marks{1}
            \item the interquartile range
            \AnswerLine[][km]
            \Marks{2}
        \end{subsubparts}
        \item One of these motorists is picked at random.

        \vgap

        Find the probability that this motorist travels more than $1800$ km.
        \AnswerLine[][]
        \Marks{2}
    \end{subparts}

    \item The distance around a racing track is $5.104$ km. % (b)

    The time taken by a car to complete one lap of the track is $1$ min $18$ s.

    \vgap

    Calculate the average speed of the car.

    Give your answer in km/h.
    \AnswerLine[][km/h]
    \Marks{3}

    \item The top speed, $v$ km/h, of each of 160 cars is recorded. % (c)

    The histogram shows this information.

    \relinput{Figures/Q05-Histogram.tex}

    \begin{subparts}
        \item Show that there are 8 cars with a top speed in the interval $120 < v \leqslant 160$.
        \Marks{1}

        \item Calculate an estimate of the mean top speed.

        You must show all your working.
        \AnswerLine[][km/h]
        \Marks{6}
    \end{subparts}
\end{parts}

\begin{parts}
    \item Work out $2\dbinom{3}{-5} - \dbinom{-2}{-7}$. % (a)
    \hfill $\dbinom{\hspace{0.5cm}}{\hspace{0.5cm}}$

    \vgap

    \Marks{2}

    \item $\overrightarrow{MN} = \dbinom{-6}{4}$. % (b)
    \begin{subparts}
        \item $M$ is the point $(2, -5)$.

        Find the coordinates of $N$.

        \hfill (\AnswerLineShort[][], \AnswerLineShort[][])
        \Marks{1}

        \item Find $|\overrightarrow{MN}|$.
        \AnswerLine[][]
        \Marks{2}
    \end{subparts}

    \item \, % (c)

    \relinput{Figures/Q06-Trapezium.tex}

    \vgap

    $OACB$ is a trapezium with $OB = 2AC$.

    $\overrightarrow{OA} = \mathbf{a}$ and $\overrightarrow{OB} = 2\mathbf{c}$.

    $AP : PB = 4 : 1$ and $AQ = \dfrac{4}{5}AC$.
    \begin{subparts}
        \item Write each of the following in terms of $\mathbf{a}$ and $\mathbf{c}$.

        Give each answer in its simplest form.
        \begin{subsubparts}
            \item $\overrightarrow{AB}$
            \AnswerLine[][]
            \Marks{1}
            \item $\overrightarrow{CB}$
            \AnswerLine[][]
            \Marks{1}
            \item $\overrightarrow{OP}$
            \AnswerLine[][]
            \Marks{2}
            \item $\overrightarrow{QP}$
            \AnswerLine[][]
            \Marks{2}
        \end{subsubparts}

        \item Use your answers to make two statements about the relationship between lines $QP$ and $CB$.
        \vgap

        \dotfill

        \vgap

        \dotfill

        \Marks{2}
    \end{subparts}
\end{parts}

\begin{parts}
    \item \, % (a)

    \relinput{Figures/Q07-Field.tex}

    \vgap

    The diagram shows a field, $ABCD$ with $B$ north of $A$.

    $BD$ is a path across the field.

    $AB = 85$ m, $AD = 72$ m, $BD = 129$ m, angle $BDC = 39^\circ$ and angle $BCD = 60^\circ$.
    \begin{subparts}
        \item Show that angle $CBD = 81^\circ$.
        \Marks{1}

        \item Calculate $CD$.
        \AnswerLine[][m]
        \Marks{3}

        \item Show that angle $ABD = 31.6^\circ$, correct to 1 decimal place.
        \Marks{4}

        \item Find the shortest distance from $A$ to $BD$.
        \AnswerLine[][m]
        \Marks{3}

        \item Find the bearing of $B$ from $C$.
        \AnswerLine[][]
        \Marks{2}

        \item Trees are planted in the field.

        The number of trees planted is 1100 per hectare.

        \vgap

        Calculate the total number of trees planted in the field.

        $[1 \text{ hectare} = 10\,000 \text{ m}^2]$
        \AnswerLine[][]
        \Marks{4}
    \end{subparts}

    \item A rectangle has an area of $9400 \text{ cm}^2$, correct to the nearest $100 \text{ cm}^2$. % (b)

    The length of the rectangle is $80$ cm, correct to the nearest $10$ cm.

    \vgap

    Calculate the upper bound of the width of the rectangle.
    \AnswerLine[][cm]
    \Marks{3}
\end{parts}

\begin{parts}
    \item A bag contains 24 coloured beads. % (a)

    Some are red, some are blue and 10 are yellow.

    One bead is picked at random from the bag.

    \vgap

    Find the probability that
    \begin{subparts}
        \item the bead is yellow
        \AnswerLine[][]
        \Marks{1}
        \item the bead is not yellow.
        \AnswerLine[][]
        \Marks{1}
    \end{subparts}

    \item Another bag contains 5 green marbles, 6 white marbles and 4 black marbles. % (b)

    Meera picks 2 marbles at random from the bag, without replacement.

    \vgap

    Find the probability that
    \begin{subparts}
        \item the first marble is black and the second marble is white
        \AnswerLine[][]
        \Marks{2}
        \item both marbles have different colours.
        \AnswerLine[][]
        \Marks{4}
    \end{subparts}
\end{parts}

$f(x) = 2x - 5$ \qquad $g(x) = x^2 - 2x$


\begin{parts}
    \item Find % (a)
    \begin{subparts}
        \item $f(7)$
        \AnswerLine[][]
        \Marks{1}
        \item $gf(7)$
        \AnswerLine[][]
        \Marks{1}
        \item $f^{-1}(x)$.
        \AnswerLine[$f^{-1}(x) = $][]
        \Marks{2}
    \end{subparts}

    \item Find $gf(x) - 3g(x)$. \\ % (b)
    Give your answer in the form $ax^2 + bx + c$.
    \AnswerLine[][]
    \Marks{4}
\end{parts}

A curve has the equation $y = x^3 - 9x^2 - 48x$.

\begin{parts}
    \item Differentiate $x^3 - 9x^2 - 48x$. % (a)
    \AnswerLine[][]
    \Marks{2}

    \item Find the coordinates of the turning points of the graph of $y = x^3 - 9x^2 - 48x$. 

    You must show all your working.

    \hfill (\AnswerLineShort[][],\AnswerLineShort[][]) and (\AnswerLineShort[][],\AnswerLineShort[][])
    \Marks{4}

    \item Determine whether each of the turning points is a maximum or a minimum. 

    Give reasons for your answers.
    \Marks{3}
\end{parts}
